/* eslint-disable security/detect-non-literal-fs-filename */
const path = require('path');
const { writeFileSync, readFileSync, existsSync, mkdirSync } = require('fs');

const get = require('lodash/get');

const { isObject } = require('../data-type');

/**
 * @typedef { keyof typeof import('../../constants/device').DEVICE_TYPES } DeviceType
 * @typedef { import('../../page/paths').Paths } Paths
 * @typedef { { [device in DeviceType]?: Paths } } PagePathsByDevice
 * @typedef { import('../../page/navigable-page').NavigablePage } NavigablePage
 *
 * @typedef { object } DiscoveredNordicPages
 * @property { boolean } hasBuild
 * @property { string | undefined } baseHooksFile
 * @property { NavigablePage[] } discoveredNavigablePages
 * @property { { [statusError: string]: { paths: PagePathsByDevice } } } discoveredHttpErrorPages
 *
 * @typedef { DiscoveredNordicPages | import('./islands-manifest').IslandsManifest } JSONContent
 */

/**
 * @param { string } filePath - File path to read
 * @returns { JSONContent | {} } File content
 */
const readJsonFile = (filePath) => {
  try {
    if (!existsSync(filePath)) {
      return {};
    }

    const content = JSON.parse(readFileSync(filePath, 'utf-8'));

    return isObject(content) ? content : {};
  } catch (e) {
    return {};
  }
};

/**
 * @param { string } filePath - File path to read
 * @param { string } key - Property to get
 * @returns { any | undefined } Property value
 */
const readJsonFileProperty = (filePath, key) => {
  if (!existsSync(filePath)) {
    return undefined;
  }

  const content = readJsonFile(filePath);

  return get(content, key, undefined);
};

/**
 * @param { string } filePath - File path to write
 * @param { JSONContent } content - Content to be written to the file
 */
const writeJsonFile = (filePath, content) => {
  const fileDir = path.dirname(filePath);

  if (!existsSync(fileDir)) {
    mkdirSync(fileDir, { recursive: true });
  }

  writeFileSync(filePath, JSON.stringify(content));
};

module.exports = {
  readJsonFile,
  readJsonFileProperty,
  writeJsonFile,
};
